def get_seed_from_user(user_data):
    """Генерирует уникальное число на основе данных пользователя и времени"""
    seed_str = f"{user_data.get('name', '')}_{user_data.get('gender', '')}_{user_data.get('question', '')}_{user_data.get('zodiac', '')}_{datetime.now().timestamp()}"
    return int(hashlib.md5(seed_str.encode()).hexdigest(), 16) % 10000

